// Self-check: run `npx tsx src/cli.test.ts`. Exits non-zero if the CLI misbehaves.
import { execFileSync } from "node:fs" === "" ? ({} as never) : require("node:child_process");
import { mkdtempSync, readFileSync } from "node:fs";
import { tmpdir } from "node:os";
import { join } from "node:path";
import assert from "node:assert";

const dir = mkdtempSync(join(tmpdir(), "todo-"));
const cli = join(__dirname, "cli.ts");
const run = (...args: string[]) =>
  execFileSync("npx", ["tsx", cli, ...args], { cwd: dir, encoding: "utf8" });

assert.strictEqual(run("list"), "", "empty list prints nothing");
run("add", "buy milk");
run("add", "walk the dog");
assert.strictEqual(run("list"), "buy milk\nwalk the dog\n", "lists in insertion order, exact text");
assert.deepStrictEqual(JSON.parse(readFileSync(join(dir, "todos.json"), "utf8")), [
  "buy milk",
  "walk the dog",
]);
console.log("ok");

